mapper.select:
select orders.uuid , orders.symbol , orders.order_no , orders.direction , orders.offset , orders.volume_open , orders.lever_rate , orders.state , orders.order_price_type , orders.stop_price_loss , orders.create_time , orders.stop_price_profit , orders.price , item.name itemname, party.user_name , party.user_code , party.role_name from t_exchange_lever_apply_order orders left join tz_user party on orders.party_id = party.user_id left join t_item item on orders.symbol = item.symbol where 1 = 1
and party.role_name=#{rolename}
and orders.state=#{status}
and orders.order_no=#{orderNo}
and (party.user_code=#{userName} or party.user_name=#{userName})
and u.user_id in
#{item}
order by orders.create_time desc
